119			FromRev:          spec.FromRev,
120			Output:           output,
121			BeadEvents:       events,
122			AgentRunner:      runner,
123			ResourceChecker:  checker,
124			RateLimitMaxWait: spec.RateLimitMaxWait.Duration,
125		}
