128	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
129		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
130		if err != nil {
131			return err
132		}
133		projectRoot := resolveProjectRoot(spec.ProjectRoot, f.WorkingDir)
134		spec.ProjectRoot = projectRoot
135		if tryTargetBeadID != "" {
136			spec.Mode = executeloop.ModeOnce
137			spec.IdleInterval = executeloop.Duration{}
138		}
139	
140		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
141			spec.Profile == "" && spec.MinPower == 0 &&
142			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
143			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
144			!cmd.Flags().Changed("profile") &&
145			!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
146		autoInferPowerClass := noRoutingFlags && !projectHasRoutingConfig(projectRoot)
147	
148		if !spec.OpaquePassthrough {
149			if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, spec.Harness, spec.Model, spec.Provider); err != nil {
150				return fmt.Errorf("execute-loop: %w", err)
151			}
152		}
153	
154		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
155	
156		loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
157		loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
158		_ = os.MkdirAll(loopLogDir, 0o755)
159		loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
160		var loopSink io.Writer
161		if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
162			loopSink = lf
163			defer lf.Close() //nolint:errcheck
164		}
165	
166		probeIdent := workerprobe.Identity{
167			ProjectRoot:  projectRoot,
168			Harness:      spec.Harness,
169			Model:        spec.Model,
170			ExecutorPID:  os.Getpid(),
171			ExecutorHost: hostnameOrEmpty(),
172			StartedAt:    time.Now().UTC(),
173		}
174		probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
175		probeCtx, probeCancel := context.WithCancel(context.Background())
176		probe.Start(probeCtx)
177		defer func() {
178			probeCancel()
179			probe.Stop()
180		}()
181		if loopSink != nil {
182			loopSink = workerprobe.TeeJSONL(loopSink, probe)
183		} else {
184			loopSink = workerprobe.TeeJSONL(io.Discard, probe)
185		}
186	
187		localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
188		defer localCoord.Stop()
189	
190		var reviewer agent.BeadReviewer
191		if !spec.NoReview {
192			reviewer = &agent.DefaultBeadReviewer{
193				ProjectRoot: projectRoot,
194				BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
195				BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
196				Harness:     spec.ReviewHarness,
197				Model:       spec.ReviewModel,
198			}
199		}
200	
201		spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
202	
203		overrides := config.CLIOverrides{
204			Assignee:          resolveClaimAssignee(),
205			Harness:           spec.Harness,
206			Model:             spec.Model,
207			Provider:          spec.Provider,
208			Profile:           spec.Profile,
209			Effort:            spec.Effort,
210			MinPower:          spec.MinPower,
211			MaxPower:          spec.MaxPower,
212			OpaquePassthrough: spec.OpaquePassthrough,
213		}
214		rcfg, err := config.LoadAndResolve(projectRoot, overrides)
215		if err != nil {
216			return fmt.Errorf("load resolved config: %w", err)
217		}
218	
219		resourceChecker := buildCLIResourceChecker(projectRoot, f.resourceCheckerOverride)
220		if _, err := resourceChecker.Check(cmd.Context()); err != nil {
221			var resourceErr *agent.ResourceExhaustedError
222			if errors.As(err, &resourceErr) {
223				_, _ = fmt.Fprintln(cmd.OutOrStdout(), agent.ResourceExhaustedStopMessage)
224			}
225			return err
226		}
227	
228		var qualityRunner agent.AgentRunner
229		if f.AgentRunnerOverride != nil {
230			qualityRunner = f.AgentRunnerOverride
231		}
232		lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
233		intakeLog := cmd.OutOrStdout()
234		if dispatch.JSON == "true" {
235			intakeLog = io.Discard
236		}
237		innerIntakeHook := agent.NewPreClaimIntakeHookWithLogVerbose(projectRoot, store, rcfg, nil, qualityRunner, intakeLog, f.viperInstance.GetBool("verbose"))
238		intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
239		triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
240		decompositionHook := agent.NewPreClaimDecompositionHook(store, qualityRunner, rcfg, projectRoot)
241		recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
242			MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
243			MaxBeadCostUSD:     spec.MaxBeadCostUSD,
244		})
245	
246		harnessBilledLookup := func(harnessName string) bool {
247			svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
248			if svcErr != nil {
249				return true
250			}
251			infos, err := svc.ListHarnesses(context.Background())
252			if err != nil {
253				return true
254			}
255			for _, h := range infos {
256				if h.Name == harnessName {
257					return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
258				}
259			}
260			return true
261		}
262	
263		costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
264		profileSelector := newImplementationProfileSelector(projectRoot)
265		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
266			costCap.Add(report.Harness, report.CostUSD)
267		}
268		costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
269			if _, tripped := costCap.Tripped(); !tripped {
270				return work.StopDecision{}, agent.ExecuteBeadReport{}, false
271			}
272			spent := costCap.Spent()
273			decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
274			return decision, agent.ExecuteBeadReport{
275				Status: agent.ExecuteBeadStatusExecutionFailed,
276				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
277			}, true
278		}
279	
280		singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, inferredPolicy escalation.PowerClass, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
281			gitOps := &agent.RealGitOps{}
282			attemptProvider := spec.Provider
283			if resolvedProvider != "" {
284				attemptProvider = resolvedProvider
285			}
286			reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
287				report := agent.ReportFromExecuteBeadResult(res, string(inferredPolicy))
288				report.InferredPowerClass = string(inferredPolicy)
289				report.RequestedProfile = requestedProfile
290				report.RoutingIntentNote = routingNote
291				return report
292			}
293			loopOverrides := config.CLIOverrides{
294				Harness:           resolvedHarness,
295				Model:             resolvedModel,
296				Provider:          attemptProvider,
297				Profile:           requestedProfile,
298				Effort:            spec.Effort,
299				MinPower:          requestedMinPower,
300				MaxPower:          spec.MaxPower,
301				OpaquePassthrough: spec.OpaquePassthrough,
302			}
303			requestTimeout := spec.RequestTimeout.Duration
304			if requestTimeout > 0 {
305				loopOverrides.ProviderRequestTimeout = &requestTimeout
306			}
307			attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
308			res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
309				spec,
310				cmd.OutOrStdout(),
311				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
312				f.AgentRunnerOverride,
313				resourceChecker,
314			), gitOps)
315			if execErr != nil && res == nil {
316				return agent.ExecuteBeadReport{}, execErr
317			}
318			if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
319				return reportFromResult(res), nil
320			}
321			if execErr != nil {
322				agent.MarkResultExecutionError(res, execErr)
323				return reportFromResult(res), nil
324			}
325			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
326				targetBead, _ := store.Get(context.Background(), beadID)
327				landRes, _, landErr := agent.SubmitWithPreMergeChecks(
328					ctx, projectRoot, targetBead, res,
329					func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
330					bead.NewStore(filepath.Join(projectRoot, ".ddx")),
331					resolveClaimAssignee(), "ddx work",
332					nil,
333				)
334				if landErr == nil {
335					agent.ApplyLandResultToExecuteBeadResult(res, landRes)
336					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
337				} else {
338					agent.MarkResultLandError(projectRoot, res, landErr)
339					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
340					return reportFromResult(res), nil
341				}
342			} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
343				if res.ResultRev != "" && res.ResultRev != res.BaseRev {
344					res.Outcome = "preserved"
345				} else {
346					res.Outcome = "error"
347				}
348				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
349			} else if res != nil && res.ResultRev == res.BaseRev {
350				res.Outcome = "no-changes"
351				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
352			}
353			return reportFromResult(res), nil
354		}
355	
356		var ladderOnce sync.Once
357		var ladder escalationFloorFinder
358		loadLadder := func() escalationFloorFinder {
359			ladderOnce.Do(func() {
360				ladder = powerladder.NewLadder(nil)
361				svc, svcErr := agent.ResolveServiceFromWorkDir(projectRoot)
362				if svcErr != nil {
363					return
364				}
365				modelFilter := agentlib.ModelFilter{}
366				if spec.Harness != "" {
367					modelFilter.Harness = spec.Harness
368				}
369				modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
370				defer cancel()
371				models, listErr := svc.ListModels(modelCtx, modelFilter)
372				if listErr != nil {
373					return
374				}
375				ladder = powerladder.NewLadder(models)
376			})
377			return ladder
378		}
379	
380		worker := &agent.ExecuteBeadWorker{
381			Store:    store,
382			Reviewer: reviewer,
383			EscalationNextFloor: func(actualPower int) (int, error) {
384				return nextEscalationFloor(loadLadder(), actualPower)
385			},
386			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
387				targetBead, err := store.Get(context.Background(), beadID)
388				if err != nil {
389					return agent.ExecuteBeadReport{}, err
390				}
391				inferredPolicy := escalation.PowerClass("")
392				if autoInferPowerClass {
393					inferredPolicy = escalation.InferPowerClass(targetBead)
394				}
395				initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPowerWithInference(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder(), false)
396				if unavailable {
397					return unavailableReport, nil
398				}
399				if spec.Provider == "" && spec.Model == "" {
400					if learnedMinPower, learnedUnavailableReport, learned := recentProviderConnectivityMinPower(store, time.Now().UTC(), initialMinPower, spec.MaxPower, loadLadder()); learned {
401						if learnedUnavailableReport.Status != "" {
402							learnedUnavailableReport.BeadID = beadID
403							return learnedUnavailableReport, nil
404						}
405						if learnedMinPower > initialMinPower {
406							initialMinPower = learnedMinPower
407						}
408					}
409				}
