513	func buildAttemptMetricsHook(projectRoot string, store *bead.Store, profile string) func(agent.ExecuteBeadReport) {
514		return func(report agent.ExecuteBeadReport) {
515			if report.AttemptID == "" {
516				return
517			}
518			specID := ""
519			if report.BeadID != "" && store != nil {
520				if b, err := store.Get(context.Background(), report.BeadID); err == nil {
521					specID, _ = b.Extra["spec-id"].(string)
522				}
523			}
524			tsEnd := attemptmetrics.Rfc3339(time.Now().UTC())
525			tsStart := ""
526			if report.DurationMS > 0 {
527				start := time.Now().UTC().Add(-time.Duration(report.DurationMS) * time.Millisecond)
528				tsStart = attemptmetrics.Rfc3339(start)
529			}
530			row := attemptmetrics.AttemptRow{
531				SchemaVersion: attemptmetrics.SchemaVersion,
532				AttemptID:     report.AttemptID,
533				BeadID:        report.BeadID,
534				SessionID:     report.SessionID,
535				TSStart:       tsStart,
536				TSEnd:         tsEnd,
537				Model:         report.Model,
538				Harness:       report.Harness,
539				Profile:       profile,
540				Provider:      report.Provider,
541				SpecID:        specID,
542				Outcome:       report.Status,
543				CostUSD:       report.CostUSD,
544				DurationMS:    int(report.DurationMS),
545				ReviewVerdict: report.ReviewVerdict,
546			}
547			_ = attemptmetrics.AppendRow(projectRoot, row)
548		}
549	}
