551	// projectHasRoutingConfig reports whether the project's .ddx/config.yaml pins a
552	// routing decision that should suppress DDx's zero-config powerClass inference.
553	// agent.endpoints alone is transport configuration (where providers live) and
554	// does NOT pin routing — leaving it on the suppression list caused no-flag work
555	// in projects with local endpoints to send an empty Policy and inherit
556	// Fizeau's default policy (which, with no DDx-supplied hint, scored Opus on
557	// ordinary implementation work; see ddx-e0b95b4a).
558	func projectHasRoutingConfig(projectRoot string) bool {
559		if projectRoot == "" {
560			return false
561		}
562		cfgPath := filepath.Join(projectRoot, ".ddx", "config.yaml")
563		if _, err := os.Stat(cfgPath); err != nil {
564			return false
565		}
566		cfg, err := config.LoadWithWorkingDir(projectRoot)
567		if err != nil || cfg == nil || cfg.Agent == nil {
568			return false
569		}
570		a := cfg.Agent
571		return strings.TrimSpace(a.Model) != ""
572	}
